import os
import re
import base64

app_path = "C:/Users/82102/Desktop/workspace/SRinspector/app.js"
with open(app_path, "r", encoding="utf-8") as f:
    code = f.read()

# Base64 encoded JavaScript string for renderSubjectGroupView to avoid any escaping/interpolation issues
# The base64 string corresponds to the function implementation
b64_func = ""

new_func = base64.b64decode(b64_func).decode('utf-8')

old_func_pattern = r"function renderSubjectGroupView\(\) \{[\s\S]*?(?=\n\nfunction|\n//|\n$)"
code = re.sub(old_func_pattern, new_func, code, count=1)

with open(app_path, "w", encoding="utf-8") as f:
    f.write(code)

print("Patch applied for subject view")
